const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const meta = data.metadata || {};
const msg = data.message || data;

const direction = (meta.eventType || msg.direction || '').toLowerCase().includes('inbound') ? 'inbound' : 'outbound';
const conversation_uid = data.conversationUid || msg.conversationUid || msg.contactUid || '';
const message_uid = msg.uid || msg.id || data.uid || '';
const message_body = msg.body || msg.text || '';
const contact_name = data.contact?.name || msg.contactName || '';
const channel_type = (data.channel?.type || msg.channelType || '').toLowerCase();
const channel_identifier = data.channel?.identifier || msg.channelIdentifier || '';

return [{ json: { direction, conversation_uid, message_uid, message_body, contact_name, channel_type, channel_identifier } }];

