const STAGE_UID = {
  'New Enquiry':  'YOUR_NEW_ENQUIRY_STAGE_UID',
  'Contacted':    'YOUR_CONTACTED_STAGE_UID',
  'Booked In':    'YOUR_BOOKED_IN_STAGE_UID',
  'In Workshop':  'YOUR_IN_WORKSHOP_STAGE_UID',
  'Quote Sent':   'YOUR_QUOTE_SENT_STAGE_UID',
  'Approved':     'YOUR_APPROVED_STAGE_UID',
  'Won':          'YOUR_WON_STAGE_UID',
  'Lost':         'YOUR_LOST_STAGE_UID',
  'Rebooked':     'YOUR_REBOOKED_STAGE_UID',
  'Unqualified':  'YOUR_UNQUALIFIED_STAGE_UID'
};
const r = $input.first().json;
const raw = r.content?.[0]?.text || r.message?.content?.[0]?.text || r.text || '';
let parsed = {};
try { parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{}'); } catch (e) { parsed = {}; }
const src = $('Extract Message Context').first().json;
const stage_uid = parsed.funnel_stage ? STAGE_UID[parsed.funnel_stage] : null;
return [{ json: {
  conversation_uid: src.conversation_uid,
  channel_identifier: src.channel_identifier,
  channel_type: src.channel_type,
  contact_name: parsed.contact_name || src.contact_name || '',
  funnel_stage: parsed.funnel_stage,
  funnel_stage_uid: stage_uid,
  opp_value_cents: parsed.opp_value_cents || null
}}];

const STAGE_ATTR = 'YOUR_FUNNEL_STAGE_ATTRIBUTE_UID';
const LOCATION_UID = 'YOUR_PODIUM_LOCATION_UID';
const contact = $input.first().json || {};
const trigger = $('Parse Claude Output').first().json;
const attr = (contact.attributes || []).find(a => a.uid === STAGE_ATTR);
const current = attr?.value || null;
const target = trigger.funnel_stage_uid;

const chType = (trigger.channel_type || '').toLowerCase();
const chId = trigger.channel_identifier || null;
let phone = chType === 'phone' ? chId : null;
let email = chType === 'email' ? chId : null;
phone = phone || (contact.phoneNumbers && contact.phoneNumbers[0]) || null;
email = email || (contact.emails && contact.emails[0]) || null;
const name = contact.name || trigger.contact_name || 'Contact';

const body = { name, locations: [LOCATION_UID], attributes: [{ uid: STAGE_ATTR, value: target }] };
if (phone) body.phoneNumber = phone;
if (email) body.email = email;

return [{ json: {
  conversation_uid: trigger.conversation_uid,
  funnel_stage_uid: target,
  funnel_stage: trigger.funnel_stage,
  current_stage_uid: current,
  should_write: current !== target,
  request_body: JSON.stringify(body),
  name,
  channel_identifier: chId || phone || email || '',
  channel_type: chType || (phone ? 'phone' : email ? 'email' : '')
}}];

const VALUE_ATTR = 'YOUR_OPP_VALUE_ATTRIBUTE_UID';
const LOCATION_UID = 'YOUR_PODIUM_LOCATION_UID';
const contact = $input.first().json || {};
const trigger = $('Parse Claude Output').first().json;
const attr = (contact.attributes || []).find(a => a.uid === VALUE_ATTR);
const current = Number(attr?.value ?? 0);
const target = Number(trigger.opp_value_cents);

const chType = (trigger.channel_type || '').toLowerCase();
const chId = trigger.channel_identifier || null;
let phone = chType === 'phone' ? chId : null;
let email = chType === 'email' ? chId : null;
phone = phone || (contact.phoneNumbers && contact.phoneNumbers[0]) || null;
email = email || (contact.emails && contact.emails[0]) || null;
const name = contact.name || trigger.contact_name || 'Contact';

const body = { name, locations: [LOCATION_UID], attributes: [{ uid: VALUE_ATTR, value: String(target) }] };
if (phone) body.phoneNumber = phone;
if (email) body.email = email;

return [{ json: {
  conversation_uid: trigger.conversation_uid,
  target_cents: target,
  current_cents: current,
  should_write: !current || target > current,
  request_body: JSON.stringify(body),
  name,
  channel_identifier: chId || phone || email || '',
  channel_type: chType || (phone ? 'phone' : email ? 'email' : '')
}}];

const QUOTE_SENT = 'YOUR_QUOTE_SENT_STAGE_UID';
const LOST       = 'YOUR_LOST_STAGE_UID';
const APPROVED   = 'YOUR_APPROVED_STAGE_UID';
const WON        = 'YOUR_WON_STAGE_UID';
const REBOOKED   = 'YOUR_REBOOKED_STAGE_UID';
const TERMINAL = new Set([APPROVED, LOST, WON, REBOOKED]);
const TIMEZONE = 'Australia/Sydney';

const now = new Date();
const rows = $input.all().map(r => r.json);

// Business hours guard (Mon–Sat 08:00–18:00 in TIMEZONE)
const local = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
const hr = local.getHours(), dow = local.getDay();
if (dow === 0 || hr < 8 || hr >= 18) return [];

const byUid = {};
for (const r of rows) {
  if (!r.conversation_uid) continue;
  const ts = r.timestamp ? new Date(r.timestamp).getTime() : 0;
  const c = byUid[r.conversation_uid] = byUid[r.conversation_uid] || {
    uid: r.conversation_uid, name: '', phone: '', email: '', channel_type: '',
    quote_sent_at: 0, current_stage: null, last_stage_ts: 0, drip_count: 0, moved_off_quote: false
  };
  if (r.name) c.name = r.name;
  if (r.channel_identifier) {
    if ((r.channel_type || '').toLowerCase() === 'email') c.email = r.channel_identifier;
    else c.phone = r.channel_identifier;
    c.channel_type = r.channel_type || c.channel_type;
  }
  if (r.action === 'FUNNEL_STAGE_SET' && r.funnel_stage_uid && ts >= c.last_stage_ts) {
    c.current_stage = r.funnel_stage_uid;
    c.last_stage_ts = ts;
    if (r.funnel_stage_uid === QUOTE_SENT) c.quote_sent_at = ts;
    if (TERMINAL.has(r.funnel_stage_uid)) c.moved_off_quote = true;
  }
  if (r.action && r.action.startsWith('DRIP_SENT')) {
    c.drip_count = Math.max(c.drip_count, Number(r.action.replace('DRIP_SENT_','')) || 1);
  }
}

const out = [];
for (const uid in byUid) {
  const c = byUid[uid];
  if (c.current_stage !== QUOTE_SENT) continue;
  if (c.moved_off_quote) continue;
  if (!c.phone && !c.email) continue;
  if (!c.quote_sent_at) continue;
  const hours = (now.getTime() - c.quote_sent_at) / 3600000;
  let next = 0;
  if (c.drip_count === 0 && hours >= 48)  next = 1;
  if (c.drip_count === 1 && hours >= 120) next = 2;
  if (c.drip_count === 2 && hours >= 240) next = 3;
  if (!next) continue;
  const firstName = (c.name || '').split(' ')[0] || 'there';
  const bodies = {
    1: `Hi ${firstName}, just checking in on the quote we sent through — happy to answer any questions.`,
    2: `Hi ${firstName}, wanted to make sure the quote landed. Keen to help whenever suits.`,
    3: `Hi ${firstName}, last check-in on the quote. If now's not the right time we'll close this out — just reply to keep it open.`
  };
  out.push({ json: {
    conversation_uid: uid, name: c.name,
    channel_identifier: c.phone || c.email,
    channel_type: c.phone ? 'phone' : 'email',
    drip_step: next, sms_body: bodies[next],
    move_to_lost: next === 3
  }});
}
return out;

const QUOTE_SENT  = 'YOUR_QUOTE_SENT_STAGE_UID';
const IN_WORKSHOP = 'YOUR_IN_WORKSHOP_STAGE_UID';
const NEW_ENQ     = 'YOUR_NEW_ENQUIRY_STAGE_UID';
const CONTACTED   = 'YOUR_CONTACTED_STAGE_UID';
const BOOKED_IN   = 'YOUR_BOOKED_IN_STAGE_UID';
const APPROVED    = 'YOUR_APPROVED_STAGE_UID';
const STAGE_LABEL = { [NEW_ENQ]:'New Enquiry', [CONTACTED]:'Contacted', [BOOKED_IN]:'Booked In', [IN_WORKSHOP]:'In Workshop', [QUOTE_SENT]:'Quote Sent', [APPROVED]:'Approved' };
const ACTIVE = new Set([NEW_ENQ, CONTACTED, BOOKED_IN, IN_WORKSHOP, QUOTE_SENT, APPROVED]);

const now = new Date(), nowMs = now.getTime();
const rows = $input.all().map(r => r.json);
const byUid = {};
for (const r of rows) {
  if (!r.conversation_uid) continue;
  const ts = r.timestamp ? new Date(r.timestamp).getTime() : 0;
  const c = byUid[r.conversation_uid] = byUid[r.conversation_uid] || { uid:r.conversation_uid, name:'', channel_identifier:'', current_stage:null, last_stage_ts:0, last_value_cents:0 };
  if (r.name) c.name = r.name;
  if (r.channel_identifier) c.channel_identifier = r.channel_identifier;
  if (r.action === 'FUNNEL_STAGE_SET' && r.funnel_stage_uid && ts >= c.last_stage_ts) { c.current_stage = r.funnel_stage_uid; c.last_stage_ts = ts; }
  if (r.action === 'OPP_VALUE_SET' && r.opp_value_cents) c.last_value_cents = Number(r.opp_value_cents) || 0;
}
const contacts = Object.values(byUid);
const H48 = 48*3600*1000, H24 = 24*3600*1000;
const stuck = contacts.filter(c => ACTIVE.has(c.current_stage) && (nowMs - c.last_stage_ts) >= H48);
const quotesWaiting = contacts.filter(c => c.current_stage === QUOTE_SENT && (nowMs - c.last_stage_ts) >= H24);
const workshopLong = contacts.filter(c => c.current_stage === IN_WORKSHOP && (nowMs - c.last_stage_ts) >= H24);
const start = new Date(now); start.setHours(0,0,0,0);
const newToday = contacts.filter(c => c.last_stage_ts >= start.getTime());
const fmtAUD = n => '$' + Math.round((Number(n)||0)/100).toLocaleString('en-US');
const fmtHrs = ms => { const h = Math.floor(ms/3600000); return h<24?h+'h':Math.floor(h/24)+'d '+(h%24)+'h'; };
const row = c => `<tr><td>${c.name||c.uid}</td><td>${STAGE_LABEL[c.current_stage]||'-'}</td><td>${c.channel_identifier}</td><td>${fmtHrs(nowMs-c.last_stage_ts)}</td><td style=\"text-align:right\">${c.last_value_cents?fmtAUD(c.last_value_cents):'-'}</td></tr>`;
const tbl = list => list.length ? list.map(row).join('') : '<tr><td colspan=\"5\" style=\"text-align:center;color:#888;padding:14px\">Nothing to flag</td></tr>';
const pipeline = contacts.filter(c => ACTIVE.has(c.current_stage)).reduce((s,c)=>s+c.last_value_cents,0);
const date = now.toLocaleDateString('en-US', { weekday:'long', day:'numeric', month:'short', year:'numeric' });
const html = `<div style=\"font:14px -apple-system,Segoe UI,sans-serif;max-width:780px;margin:0 auto;color:#1f2328\"><h1 style=\"font-size:22px\">Daily Pipeline Report</h1><p style=\"color:#656d76\">${date}</p><p>Active pipeline value: <strong>${fmtAUD(pipeline)}</strong></p><h2 style=\"font-size:16px;border-bottom:2px solid #ffa657;padding-bottom:6px\">🟠 Quotes awaiting reply &gt; 24h (${quotesWaiting.length})</h2><table style=\"width:100%;border-collapse:collapse;font-size:13px\"><thead><tr style=\"background:#f6f8fa\"><th style=\"text-align:left;padding:8px;border:1px solid #d0d7de\">Name</th><th style=\"text-align:left;padding:8px;border:1px solid #d0d7de\">Stage</th><th style=\"text-align:left;padding:8px;border:1px solid #d0d7de\">Channel</th><th style=\"text-align:left;padding:8px;border:1px solid #d0d7de\">In stage</th><th style=\"text-align:right;padding:8px;border:1px solid #d0d7de\">Value</th></tr></thead><tbody>${tbl(quotesWaiting)}</tbody></table><h2 style=\"font-size:16px;border-bottom:2px solid #d29922;padding-bottom:6px\">🔧 In Workshop &gt; 24h (${workshopLong.length})</h2><table style=\"width:100%;border-collapse:collapse;font-size:13px\"><tbody>${tbl(workshopLong)}</tbody></table><h2 style=\"font-size:16px;border-bottom:2px solid #cf222e;padding-bottom:6px\">⚠️ Stuck in stage &gt; 48h (${stuck.length})</h2><table style=\"width:100%;border-collapse:collapse;font-size:13px\"><tbody>${tbl(stuck)}</tbody></table><h2 style=\"font-size:16px;border-bottom:2px solid #3fb950;padding-bottom:6px\">🆕 Moved today (${newToday.length})</h2><table style=\"width:100%;border-collapse:collapse;font-size:13px\"><tbody>${tbl(newToday)}</tbody></table></div>`;
return [{ json: { html, subject: `Daily Pipeline Report - ${date}` } }];

const STAGE_LABEL = {
  'YOUR_NEW_ENQUIRY_STAGE_UID':'New Enquiry',
  'YOUR_CONTACTED_STAGE_UID':'Contacted',
  'YOUR_BOOKED_IN_STAGE_UID':'Booked In',
  'YOUR_IN_WORKSHOP_STAGE_UID':'In Workshop',
  'YOUR_QUOTE_SENT_STAGE_UID':'Quote Sent',
  'YOUR_APPROVED_STAGE_UID':'Approved',
  'YOUR_WON_STAGE_UID':'Won',
  'YOUR_LOST_STAGE_UID':'Lost',
  'YOUR_REBOOKED_STAGE_UID':'Rebooked',
  'YOUR_UNQUALIFIED_STAGE_UID':'Unqualified'
};
const STAGE_ORDER = Object.keys(STAGE_LABEL);
const rows = $input.all().map(r => r.json).filter(r => r.conversation_uid);
const now = Date.now();
const fmtAUD = n => '$' + Math.round((Number(n)||0)/100).toLocaleString('en-US');
const fmtDate = ts => { const d = (now - ts) / 60000; if (d < 60) return Math.floor(d)+'m'; if (d < 1440) return Math.floor(d/60)+'h'; return Math.floor(d/1440)+'d'; };
const hash = s => { let h = 0; for (let i=0;i<s.length;i++) h = (h*31+s.charCodeAt(i))|0; return Math.abs(h); };
const colors = ['#7c3aed','#0ea5e9','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4','#84cc16'];

// Build cards per stage from latest stage-set events
const byUid = {};
for (const r of rows) {
  const ts = r.timestamp ? new Date(r.timestamp).getTime() : 0;
  const c = byUid[r.conversation_uid] = byUid[r.conversation_uid] || { uid:r.conversation_uid, name:r.name||'', channel:r.channel_identifier||'', value:0, stage:null, ts:0 };
  if (r.name) c.name = r.name;
  if (r.channel_identifier) c.channel = r.channel_identifier;
  if (r.action === 'FUNNEL_STAGE_SET' && r.funnel_stage_uid && ts >= c.ts) { c.stage = r.funnel_stage_uid; c.ts = ts; }
  if (r.action === 'OPP_VALUE_SET' && r.opp_value_cents) c.value = Number(r.opp_value_cents) || c.value;
}
const contacts = Object.values(byUid).filter(c => c.stage);
const byStage = {};
for (const s of STAGE_ORDER) byStage[s] = [];
for (const c of contacts) if (byStage[c.stage]) byStage[c.stage].push(c);
for (const s in byStage) byStage[s].sort((a,b)=>b.ts-a.ts);

const card = c => {
  const initials = (c.name||'?').split(' ').map(w=>w[0]).slice(0,2).join('').toUpperCase();
  const color = colors[hash(c.name||c.uid) % colors.length];
  return `<div style=\"background:white;border:1px solid #e5e7eb;border-radius:8px;padding:10px;margin-bottom:8px;box-shadow:0 1px 2px rgba(0,0,0,.04)\"><div style=\"display:flex;align-items:center;gap:8px;margin-bottom:6px\"><div style=\"width:28px;height:28px;border-radius:50%;background:${color};color:white;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:600\">${initials}</div><div style=\"flex:1;font-size:13px;font-weight:600;color:#111827\">${c.name||'Contact'}</div></div><div style=\"font-size:11px;color:#6b7280\">${c.channel||''}</div><div style=\"display:flex;justify-content:space-between;margin-top:6px;font-size:11px\"><span style=\"color:#059669;font-weight:600\">${c.value?fmtAUD(c.value):''}</span><span style=\"color:#9ca3af\">${fmtDate(c.ts)}</span></div></div>`;
};
const col = s => `<div style=\"flex:0 0 240px;background:#f3f4f6;border-radius:10px;padding:10px;margin-right:10px\"><div style=\"font-size:12px;font-weight:700;text-transform:uppercase;color:#374151;margin-bottom:10px;display:flex;justify-content:space-between\"><span>${STAGE_LABEL[s]}</span><span style=\"background:white;border-radius:10px;padding:1px 8px;font-size:11px\">${byStage[s].length}</span></div>${byStage[s].map(card).join('')||'<div style=\"color:#9ca3af;font-size:12px;text-align:center;padding:20px 0\">Empty</div>'}</div>`;

const ACTIVE_UIDS = STAGE_ORDER.slice(0, 6);
const pipeline = contacts.filter(c => ACTIVE_UIDS.includes(c.stage)).reduce((s,c)=>s+c.value,0);
const won = contacts.filter(c => c.stage === 'YOUR_WON_STAGE_UID').reduce((s,c)=>s+c.value,0);
const rebooked = contacts.filter(c => c.stage === 'YOUR_REBOOKED_STAGE_UID').length;
const valued = contacts.filter(c => c.value > 0);
const avg = valued.length ? Math.round(valued.reduce((s,c)=>s+c.value,0)/valued.length) : 0;

const html = `<!DOCTYPE html><html><head><meta charset=\"utf-8\"><title>Pipeline Dashboard</title><style>body{margin:0;font-family:-apple-system,Segoe UI,Roboto,sans-serif;background:#f9fafb;color:#111827}</style></head><body><div style=\"max-width:1600px;margin:0 auto;padding:20px\"><h1 style=\"font-size:24px;margin:0 0 16px\">Pipeline Dashboard</h1><div style=\"display:flex;gap:12px;margin-bottom:24px;flex-wrap:wrap\"><div style=\"flex:1;min-width:200px;background:white;border-radius:10px;padding:16px;border:1px solid #e5e7eb\"><div style=\"font-size:11px;color:#6b7280;text-transform:uppercase;font-weight:600\">Active pipeline</div><div style=\"font-size:24px;font-weight:700;margin-top:4px\">${fmtAUD(pipeline)}</div></div><div style=\"flex:1;min-width:200px;background:white;border-radius:10px;padding:16px;border:1px solid #e5e7eb\"><div style=\"font-size:11px;color:#6b7280;text-transform:uppercase;font-weight:600\">Avg deal size</div><div style=\"font-size:24px;font-weight:700;margin-top:4px\">${fmtAUD(avg)}</div></div><div style=\"flex:1;min-width:200px;background:white;border-radius:10px;padding:16px;border:1px solid #e5e7eb\"><div style=\"font-size:11px;color:#6b7280;text-transform:uppercase;font-weight:600\">Won revenue</div><div style=\"font-size:24px;font-weight:700;margin-top:4px\">${fmtAUD(won)}</div></div><div style=\"flex:1;min-width:200px;background:white;border-radius:10px;padding:16px;border:1px solid #e5e7eb\"><div style=\"font-size:11px;color:#6b7280;text-transform:uppercase;font-weight:600\">Rebooked</div><div style=\"font-size:24px;font-weight:700;margin-top:4px\">${rebooked}</div></div></div><div style=\"display:flex;overflow-x:auto;padding-bottom:20px\">${STAGE_ORDER.map(col).join('')}</div></div></body></html>`;
return [{ json: { html } }];
